        const hasSelectedEvent = !!this.state.event?.id;
        const isAdmin = this.state.user?.role === 'ADMIN';
        
        // Panel Admin - solo visible si es ADMIN Y hay evento seleccionado
        const btnAdmin = document.getElementById('nav-btn-admin');
