        const bgCard = isDark ? '#1e293b' : '#ffffff';
        const bgInput = isDark ? '#334155' : '#e2e8f0';
        const textMain = isDark ? '#f8fafc' : '#1e293b';
        const textSecondary = isDark ? '#94a3b8' : '#475569';
