if (document.readyState === 'loading') {
    // El DOM todavía no está listo, esperar al evento
    document.addEventListener('DOMContentLoaded', initApp);
} else {
    // El DOM ya está listo, ejecutar inmediatamente
    initApp();
}

// ── Global: cerrar modal al hacer clic fuera (backdrop) ──
document.addEventListener('click', (e) => {
    const backdrop = e.target.closest('[id^="modal-"]:not(.hidden)');
    if (backdrop && e.target === backdrop) {
        backdrop.classList.add('hidden');
        document.body.style.overflow = '';
        if (backdrop.closest('#modal-container-portal')) backdrop.remove();
    }
});

// ── Global: cerrar modal con Escape ──
document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') {
        const visible = document.querySelector('[id^="modal-"]:not(.hidden)');
        if (visible) {
            visible.classList.add('hidden');
            document.body.style.overflow = '';
        }
        const portal = document.querySelector('#modal-container-portal > [id^="modal-"]');
        if (portal) portal.remove();
    }
});

// ── Observer de modales: scroll lock ──
(function() {
    function updateScrollLock() {
        const visibleModal = document.querySelector('[id^="modal-"]:not(.hidden)');
        document.body.style.overflow = visibleModal ? 'hidden' : '';
    }
    const observer = new MutationObserver(updateScrollLock);
    document.querySelectorAll('[id^="modal-"]').forEach(m => {
        observer.observe(m, { attributes: true, attributeFilter: ['class'] });
    });
    const portal = document.getElementById('modal-container-portal');
    if (portal) observer.observe(portal, { childList: true, subtree: true, attributes: true, attributeFilter: ['class'] });
    const bodyObserver = new MutationObserver(() => {
        document.querySelectorAll('[id^="modal-"]').forEach(m => {
            try { observer.observe(m, { attributes: true, attributeFilter: ['class'] }); } catch(e) {}
        });
        updateScrollLock();
    });
    bodyObserver.observe(document.body, { childList: true, subtree: true });
})();

